    AcceptInvitationResponse, AddMemberRequest, CreateTeamRequest, InvitationResponse,
    InviteRequest, ListInvitationsResponse, ListMembersResponse, ListTeamsResponse, MemberResponse,
    SessionSummary, TeamDetailResponse, TeamResponse, UpdateTeamRequest,
};

use opensession_api_types::{service, ServiceError};

use crate::error::IntoErrResponse;
use crate::storage;

impl From<storage::TeamRow> for TeamResponse {
    fn from(t: storage::TeamRow) -> Self {
        Self {
            id: t.id,
            name: t.name,
            description: t.description,
            is_public: t.is_public,
            created_by: t.created_by,
            created_at: t.created_at,
        }
    }
}

impl From<storage::MemberRow> for MemberResponse {
    fn from(m: storage::MemberRow) -> Self {
        Self {
            user_id: m.user_id,
            nickname: m.nickname,
            role: m.role,
            joined_at: m.joined_at,
        }
    }
}

/// Check if a user is a team admin (has role='admin' in team_members).
async fn is_team_admin(d1: &D1Database, team_id: &str, user_id: &str) -> Result<bool> {
    let row = d1
        .prepare(db::TEAM_MEMBER_ROLE)
        .bind(&[team_id.into(), user_id.into()])?
        .first::<storage::RoleRow>(None)
        .await?;
    Ok(row.map(|r| r.role == "admin").unwrap_or(false))
}

/// POST /api/teams — create team (any authenticated user)
pub async fn create(mut req: Request, ctx: RouteContext<()>) -> Result<Response> {
    let user = match storage::require_auth(&req, &ctx.env).await {
        Ok(u) => u,
        Err(resp) => return Ok(resp),
    };

    let body: CreateTeamRequest = req.json().await?;
    let name = match service::validate_team_name(&body.name) {
        Ok(n) => n,
        Err(e) => return e.into_err_response(),
    };

    let team_id = uuid::Uuid::new_v4().to_string();
    let is_public = body.is_public.unwrap_or(false);
    let d1 = storage::get_d1(&ctx.env)?;

    // Create the team using shared INSERT query
    d1.prepare(db::TEAM_INSERT)
        .bind(&[
            team_id.clone().into(),
            name.clone().into(),
            body.description.clone().unwrap_or_default().into(),
            is_public.into(),
            user.id.clone().into(),
        ])?
        .run()
        .await?;

    // Add creator as admin member
    d1.prepare(db::MEMBER_INSERT)
        .bind(&[
            team_id.clone().into(),
            user.id.clone().into(),
            "admin".into(),
        ])?
        .run()
        .await?;

    let created_at = d1
        .prepare(db::TEAM_CREATED_AT)
        .bind(&[team_id.clone().into()])?
        .first::<storage::CreatedAtRow>(None)
        .await?
        .map(|r| r.created_at)
        .unwrap_or_default();

    let mut resp = Response::from_json(&TeamResponse {
        id: team_id,
        name,
        description: body.description,
        is_public,
        created_by: user.id,
        created_at,
    })?;
    resp = resp.with_status(201);
    Ok(resp)
}

/// GET /api/teams — list my teams
pub async fn list(req: Request, ctx: RouteContext<()>) -> Result<Response> {
