/// POST /api/invitations/:id/accept — accept an invitation
pub async fn accept_invitation(req: Request, ctx: RouteContext<()>) -> Result<Response> {
    let user = match storage::require_auth(&req, &ctx.env).await {
        Ok(u) => u,
        Err(resp) => return Ok(resp),
    };

    let inv_id = ctx.param("id").ok_or_else(|| Error::from("Missing id"))?;
    let d1 = storage::get_d1(&ctx.env)?;

    // Fetch invitation
    let inv = d1
        .prepare(db::INVITATION_LOOKUP)
        .bind(&[inv_id.clone().into()])?
        .first::<storage::InvitationLookupRow>(None)
        .await?;

    let inv = match inv {
        Some(i) => i,
        None => return ServiceError::NotFound("invitation not found".into()).into_err_response(),
    };

    if inv.status != "pending" {
        return ServiceError::BadRequest("invitation is no longer pending".into())
            .into_err_response();
    }

    // Check expiry
    let now = chrono::Utc::now().format("%Y-%m-%d %H:%M:%S").to_string();
    if inv.expires_at < now {
        return ServiceError::BadRequest("invitation has expired".into()).into_err_response();
    }

    // Verify the invitation belongs to this user
    let email_match = inv
        .email
        .as_ref()
        .filter(|e| !e.is_empty())
        .map(|e| {
            user.email
                .as_ref()
                .map(|ue| ue.to_lowercase() == e.to_lowercase())
                .unwrap_or(false)
        })
        .unwrap_or(false);

    let oauth_match = match (&inv.oauth_provider, &inv.oauth_provider_username) {
        (Some(prov), Some(uname)) if !prov.is_empty() && !uname.is_empty() => d1
            .prepare(db::OAUTH_IDENTITY_MATCH)
            .bind(&[
                user.id.clone().into(),
                prov.clone().into(),
                uname.clone().into(),
            ])?
            .first::<storage::CountRow>(None)
            .await?
            .map(|r| r.count > 0)
            .unwrap_or(false),
        _ => false,
    };

    if !email_match && !oauth_match {
        return ServiceError::Forbidden("this invitation is not for you".into())
            .into_err_response();
    }

    // Check not already a member
    let already = d1
        .prepare(db::TEAM_MEMBER_EXISTS)
        .bind(&[inv.team_id.clone().into(), user.id.clone().into()])?
        .first::<storage::CountRow>(None)
        .await?
        .map(|r| r.count)
        .unwrap_or(0);

    if already > 0 {
        // Already a member — mark invitation accepted and return
        d1.prepare(db::INVITATION_UPDATE_STATUS)
            .bind(&[JsValue::from("accepted"), inv_id.clone().into()])?
            .run()
            .await?;
        return ServiceError::Conflict("already a member of this team".into()).into_err_response();
    }

    // Add as team member
    d1.prepare(db::MEMBER_INSERT)
        .bind(&[
            inv.team_id.clone().into(),
            user.id.clone().into(),
            inv.role.clone().into(),
        ])?
        .run()
        .await?;

    // Mark invitation accepted
    d1.prepare(db::INVITATION_UPDATE_STATUS)
        .bind(&[JsValue::from("accepted"), inv_id.clone().into()])?
        .run()
        .await?;

    Response::from_json(&AcceptInvitationResponse {
        team_id: inv.team_id,
        role: inv.role,
    })
}

/// POST /api/invitations/:id/decline — decline an invitation
