use worker::*;

use opensession_api_types::{db, ServiceError, SessionSummary, SyncPullResponse};

use crate::error::IntoErrResponse;
use crate::storage;

/// `GET /api/sync/pull` — incremental pull of team sessions.
///
/// Returns sessions uploaded after the given cursor (`since`), ordered by `uploaded_at ASC`.
/// The client should store `next_cursor` and pass it as `since` on the next call.
pub async fn pull(req: Request, ctx: RouteContext<()>) -> Result<Response> {
    let user = match storage::require_auth(&req, &ctx.env).await {
        Ok(u) => u,
        Err(resp) => return Ok(resp),
    };

    let url = req.url()?;
    let pairs: Vec<(String, String)> = url.query_pairs().into_owned().collect();

    let team_id = match pairs.iter().find(|(k, _)| k == "team_id") {
        Some((_, v)) => v.clone(),
        None => {
            return ServiceError::BadRequest("team_id is required".into()).into_err_response();
        }
    };
    let since = pairs
        .iter()
        .find(|(k, _)| k == "since")
        .map(|(_, v)| v.clone());
    let limit = pairs
        .iter()
        .find(|(k, _)| k == "limit")
        .and_then(|(_, v)| v.parse::<u32>().ok())
        .unwrap_or(100)
        .clamp(1, 500) as i64;

    // Verify team membership
    let d1 = storage::get_d1(&ctx.env)?;
    let member_check = d1
        .prepare(db::TEAM_MEMBER_EXISTS)
        .bind(&[team_id.clone().into(), user.id.into()])?
        .first::<storage::CountRow>(None)
        .await?;

    if member_check.map(|r| r.count).unwrap_or(0) == 0 {
        return ServiceError::Forbidden("not a member of this team".into()).into_err_response();
    }

    let (sql, params): (String, Vec<wasm_bindgen::JsValue>) = if let Some(ref cursor) = since {
        (
            format!(
                "SELECT {} \
                 FROM sessions s LEFT JOIN users u ON u.id = s.user_id \
                 WHERE s.team_id = ?1 AND s.uploaded_at > ?2 \
                 ORDER BY s.uploaded_at ASC \
                 LIMIT ?3",
                db::SESSION_COLUMNS
            ),
            vec![team_id.into(), cursor.clone().into(), (limit as f64).into()],
        )
    } else {
        (
            format!(
                "SELECT {} \
                 FROM sessions s LEFT JOIN users u ON u.id = s.user_id \
                 WHERE s.team_id = ?1 \
                 ORDER BY s.uploaded_at ASC \
                 LIMIT ?2",
                db::SESSION_COLUMNS
            ),
            vec![team_id.into(), (limit as f64).into()],
        )
    };

    let rows_result = d1.prepare(&sql).bind(&params)?.all().await?;

    let sessions: Vec<SessionSummary> = rows_result
        .results::<storage::SessionRow>()?
        .into_iter()
        .map(SessionSummary::from)
        .collect();

    let has_more = sessions.len() as i64 == limit;
    let next_cursor = if has_more {
        sessions.last().map(|s| s.uploaded_at.clone())
    } else {
        None
    };

    Response::from_json(&SyncPullResponse {
        sessions,
        next_cursor,
        has_more,
    })
}

use axum::{
    extract::{Query, State},
    Json,
};

use opensession_api_types::{db, SessionSummary, SyncPullQuery, SyncPullResponse};

use crate::error::ApiErr;
use crate::routes::[REDACTED_CREDENTIAL]
use crate::storage::{session_from_row, Db};

/// `GET /api/sync/pull` — incremental pull of team sessions.
///
/// Returns sessions uploaded after the given cursor (`since`), ordered by `uploaded_at ASC`.
/// The client should store `next_cursor` and pass it as `since` on the next call.
pub async fn pull(
    State(db): State<Db>,
    user: AuthUser,
    Query(q): Query<SyncPullQuery>,
) -> Result<Json<SyncPullResponse>, ApiErr> {
    if !db.is_team_member(&q.team_id, &user.user_id) {
        return Err(ApiErr::forbidden("not a member of this team"));
    }

    let conn = db.conn();
    let limit = q.limit.unwrap_or(100).clamp(1, 500) as i64;

    // Cursor format: "{uploaded_at}\n{session_id}" (opaque to clients).
    let (sql, params): (String, Vec<Box<dyn rusqlite::types::ToSql>>) =
        if let Some(ref since) = q.since {
            if let Some((ts, last_id)) = since.split_once('\n') {
                // Keyset pagination: skip past the exact (uploaded_at, id) pair.
                (
                    format!(
                        "SELECT {} \
                     FROM sessions s LEFT JOIN users u ON u.id = s.user_id \
                     WHERE s.team_id = ?1 \
                       AND (s.uploaded_at > ?2 OR (s.uploaded_at = ?2 AND s.id > ?3)) \
                     ORDER BY s.uploaded_at ASC, s.id ASC \
                     LIMIT ?4",
                        db::SESSION_COLUMNS
                    ),
                    vec![
                        Box::new(q.team_id.clone()),
                        Box::new(ts.to_owned()),
                        Box::new(last_id.to_owned()),
                        Box::new(limit),
                    ],
                )
            } else {
                // Legacy cursor (plain timestamp) — best-effort.
                (
                    format!(
                        "SELECT {} \
                     FROM sessions s LEFT JOIN users u ON u.id = s.user_id \
                     WHERE s.team_id = ?1 AND s.uploaded_at > ?2 \
                     ORDER BY s.uploaded_at ASC, s.id ASC \
                     LIMIT ?3",
                        db::SESSION_COLUMNS
                    ),
                    vec![
                        Box::new(q.team_id.clone()),
                        Box::new(since.clone()),
                        Box::new(limit),
                    ],
                )
            }
        } else {
            (
                format!(
                    "SELECT {} \
                 FROM sessions s LEFT JOIN users u ON u.id = s.user_id \
                 WHERE s.team_id = ?1 \
                 ORDER BY s.uploaded_at ASC, s.id ASC \
                 LIMIT ?2",
                    db::SESSION_COLUMNS
                ),
                vec![Box::new(q.team_id.clone()), Box::new(limit)],
            )
        };

    let mut stmt = conn
        .prepare(&sql)
        .map_err(ApiErr::from_db("prepare pull"))?;
    let param_refs: Vec<&dyn rusqlite::types::ToSql> = params.iter().map(|p| p.as_ref()).collect();
    let rows = stmt
        .query_map(param_refs.as_slice(), session_from_row)
        .map_err(ApiErr::from_db("pull sessions"))?;

    let sessions: Vec<SessionSummary> = rows.filter_map(|r| r.ok()).collect();

    let has_more = sessions.len() as i64 == limit;
    let next_cursor = if has_more {
        sessions
            .last()
            .map(|s| format!("{}\n{}", s.uploaded_at, s.id))
    } else {
        None
    };

    Ok(Json(SyncPullResponse {
        sessions,
        next_cursor,
        has_more,
    }))
}

use axum::{
    extract::{Path, State},
    http::StatusCode,
    Json,
};
use uuid::Uuid;

use opensession_api_types::{
    db, service, AcceptInvitationResponse, AddMemberRequest, CreateTeamRequest, InvitationResponse,
    InviteRequest, ListInvitationsResponse, ListMembersResponse, ListTeamsResponse, MemberResponse,
    OkResponse, SessionSummary, TeamDetailResponse, TeamResponse, UpdateTeamRequest,
};

