/// POST /api/invitations/:id/accept — accept an invitation.
pub async fn accept_invitation(
    State(db): State<Db>,
    user: AuthUser,
    Path(inv_id): Path<String>,
) -> Result<Json<AcceptInvitationResponse>, ApiErr> {
    let conn = db.conn();

    // Fetch invitation
    let inv = conn
        .query_row(db::INVITATION_LOOKUP, [&inv_id], |row| {
            Ok((
                row.get::<_, String>(0)?,         // id
                row.get::<_, String>(1)?,         // team_id
                row.get::<_, Option<String>>(2)?, // email
                row.get::<_, Option<String>>(3)?, // oauth_provider
                row.get::<_, Option<String>>(4)?, // oauth_provider_username
                row.get::<_, String>(5)?,         // role
                row.get::<_, String>(6)?,         // status
                row.get::<_, String>(7)?,         // expires_at
            ))
        })
        .map_err(|_| ApiErr::not_found("invitation not found"))?;

    let (_inv_id, team_id, inv_email, inv_prov, inv_uname, role, status, expires_at) = inv;

    if status != "pending" {
        return Err(ApiErr::bad_request("invitation is no longer pending"));
    }

    let now = chrono::Utc::now().format("%Y-%m-%d %H:%M:%S").to_string();
    if expires_at < now {
        return Err(ApiErr::bad_request("invitation has expired"));
    }

    // Verify ownership
    let email_match = inv_email
        .as_ref()
        .filter(|e| !e.is_empty())
        .map(|e| {
            user.email
                .as_ref()
                .map(|ue| ue.to_lowercase() == e.to_lowercase())
                .unwrap_or(false)
        })
        .unwrap_or(false);

    let oauth_match = match (&inv_prov, &inv_uname) {
        (Some(prov), Some(uname)) if !prov.is_empty() && !uname.is_empty() => conn
            .query_row(
                db::OAUTH_IDENTITY_MATCH,
                rusqlite::params![&user.user_id, prov, uname],
                |row| row.get::<_, i64>(0),
            )
            .map(|c| c > 0)
            .unwrap_or(false),
        _ => false,
    };

    if !email_match && !oauth_match {
        return Err(ApiErr::forbidden("this invitation is not for you"));
    }

    // Check not already a member
    let already: bool = conn
        .query_row(
            db::TEAM_MEMBER_EXISTS,
            rusqlite::params![&team_id, &user.user_id],
            |row| row.get::<_, i64>(0).map(|c| c > 0),
        )
        .unwrap_or(false);

    if already {
        conn.execute(
            db::INVITATION_UPDATE_STATUS,
            rusqlite::params!["accepted", &inv_id],
        )
        .ok();
        return Err(ApiErr::conflict("already a member of this team"));
    }

    // Add as team member
    conn.execute(
        db::MEMBER_INSERT,
        rusqlite::params![&team_id, &user.user_id, &role],
    )
    .map_err(|e| {
        tracing::error!("accept invitation: {e}");
        ApiErr::internal("failed to join team")
    })?;

    // Mark invitation accepted
    conn.execute(
        db::INVITATION_UPDATE_STATUS,
        rusqlite::params!["accepted", &inv_id],
    )
    .ok();

    Ok(Json(AcceptInvitationResponse { team_id, role }))
}

/// POST /api/invitations/:id/decline — decline an invitation.
pub async fn decline_invitation(
    State(db): State<Db>,
    user: AuthUser,
    Path(inv_id): Path<String>,
) -> Result<Json<OkResponse>, ApiErr> {
    let conn = db.conn();

    // Fetch invitation
    let inv = conn
        .query_row(db::INVITATION_LOOKUP, [&inv_id], |row| {
            Ok((
                row.get::<_, Option<String>>(2)?, // email
                row.get::<_, Option<String>>(3)?, // oauth_provider
                row.get::<_, Option<String>>(4)?, // oauth_provider_username
                row.get::<_, String>(6)?,         // status
            ))
        })
        .map_err(|_| ApiErr::not_found("invitation not found"))?;

    let (inv_email, inv_prov, inv_uname, status) = inv;

    if status != "pending" {
        return Err(ApiErr::bad_request("invitation is no longer pending"));
    }

    // Verify ownership
    let email_match = inv_email
        .as_ref()
        .filter(|e| !e.is_empty())
        .map(|e| {
            user.email
                .as_ref()
                .map(|ue| ue.to_lowercase() == e.to_lowercase())
                .unwrap_or(false)
        })
        .unwrap_or(false);

    let oauth_match = match (&inv_prov, &inv_uname) {
        (Some(prov), Some(uname)) if !prov.is_empty() && !uname.is_empty() => conn
            .query_row(
                db::OAUTH_IDENTITY_MATCH,
                rusqlite::params![&user.user_id, prov, uname],
                |row| row.get::<_, i64>(0),
            )
            .map(|c| c > 0)
            .unwrap_or(false),
        _ => false,
    };

    if !email_match && !oauth_match {
        return Err(ApiErr::forbidden("this invitation is not for you"));
    }

    conn.execute(
        db::INVITATION_UPDATE_STATUS,
        rusqlite::params!["declined", &inv_id],
    )
    .ok();

    Ok(Json(OkResponse { ok: true }))
}

use anyhow::{ensure, Result};

use opensession_api_types::{SyncPullResponse, UploadRequest};

use crate::client::TestContext;
use crate::fixtures;

/// GET /api/sync/pull?team_id=X returns uploaded sessions.
pub async fn sync_pull_basic(ctx: &TestContext) -> Result<()> {
    let (user, team_id) = ctx.setup_user_with_team().await?;

    let session = fixtures::minimal_session();
    ctx.post_json_authed(
        "/sessions",
        &user.access_token,
        &UploadRequest {
            session: fixtures::session_to_value(&session),
            team_id: Some(team_id.clone()),
            body_url: None,
            linked_session_ids: None,
        },
    )
    .await?;

    let resp = ctx
        .get_authed(&format!("/sync/pull?team_id={team_id}"), &user.access_token)
        .await?;
    ensure!(resp.status() == 200);

    let body: SyncPullResponse = resp.json().await?;
    ensure!(!body.sessions.is_empty(), "expected at least 1 session");
    Ok(())
}

/// Cursor-based pagination with `since` param.
pub async fn sync_pull_cursor(ctx: &TestContext) -> Result<()> {
    let (user, team_id) = ctx.setup_user_with_team().await?;

    for _ in 0..3 {
        let session = fixtures::minimal_session();
        ctx.post_json_authed(
            "/sessions",
            &user.access_token,
            &UploadRequest {
                session: fixtures::session_to_value(&session),
                team_id: Some(team_id.clone()),
                body_url: None,
                linked_session_ids: None,
            },
        )
        .await?;
    }

    // Pull with limit=1
    let resp = ctx
        .get_authed(
            &format!("/sync/pull?team_id={team_id}&limit=1"),
            &user.access_token,
        )
        .await?;
    let page1: SyncPullResponse = resp.json().await?;
    ensure!(page1.sessions.len() == 1);
    ensure!(page1.has_more);
    ensure!(page1.next_cursor.is_some());

    // Pull with cursor
    let cursor = page1.next_cursor.as_ref().unwrap();
    let resp = ctx
        .get_authed(
            &format!("/sync/pull?team_id={team_id}&limit=1&since={cursor}"),
            &user.access_token,
        )
        .await?;
    let page2: SyncPullResponse = resp.json().await?;
    ensure!(page2.sessions.len() == 1);
    ensure!(
        page2.sessions[0].id != page1.sessions[0].id,
        "expected different session on page 2"
    );
    Ok(())
}

/// Non-member team → 403.
pub async fn sync_pull_non_member(ctx: &TestContext) -> Result<()> {
    let (_, team_id) = ctx.setup_user_with_team().await?;
    let outsider = ctx.register_user().await?;

    let resp = ctx
        .get_authed(
            &format!("/sync/pull?team_id={team_id}"),
            &outsider.access_token,
        )
        .await?;
    ensure!(resp.status() == 403, "expected 403, got {}", resp.status());
    Ok(())
}

