/** Check if the user is authenticated (has JWT or API key). */
export function isAuthenticated(): boolean {
	return !!(getAccessToken() || getApiKey());
}

// ── Request layer ───────────────────────────────────────────────────────────

/** Get the current auth header value, auto-refreshing JWT if needed. */
async function getAuthHeader(): Promise<string | null> {
	// Prefer JWT
	let token = getAccessToken();
	if (token) {
		// Check if token needs refresh
		const expiry = getTokenExpiry();
		if (expiry > 0 && Math.floor(Date.now() / 1000) >= expiry) {
			const refreshed = await tryRefreshToken();
			if (refreshed) {
				token = getAccessToken();
			} else {
				// Refresh failed, clear tokens
				clearTokens();
				token = null;
			}
		}
		if (token) return `Bearer ${token}`;
	}

	// Fall back to API key
	const apiKey = getApiKey();
	if (apiKey) return `Bearer ${apiKey}`;

	return null;
}

async function request<T>(path: string, options: RequestInit = {}): Promise<T> {
	const url = `${getBaseUrl()}${path}`;
	const headers: Record<string, string> = {
		'Content-Type': 'application/json',
		...(options.headers as Record<string, string>)
	};

	const auth = await getAuthHeader();
	if (auth) {
		headers['Authorization'] = auth;
	}

	const res = await fetch(url, {
		...options,
		headers
	});

	if (!res.ok) {
		const body = await res.text();
		throw new ApiError(res.status, body);
	}

	return res.json();
}

export class ApiError extends Error {
	constructor(
		public status: number,
		public body: string
	) {
		const msg = body.trimStart().startsWith('<')
			? `Server returned ${status}`
			: body.slice(0, 200);
		super(msg);
	}
}

// Sessions

function buildQuery(params?: Record<string, string | number | undefined>): string {
	if (!params) return '';
	const query = new URLSearchParams();
	for (const [key, val] of Object.entries(params)) {
		if (val != null) query.set(key, String(val));
	}
	const qs = query.toString();
	return qs ? `?${qs}` : '';
}

