sha2 = { version = "0.10", optional = true }
pbkdf2 = { version = "0.12", features = ["simple"], optional = true }
getrandom = { version = "0.2", optional = true }
hex = { version = "0.4", optional = true }
base64 = "0.22"
uuid = { version = "1", features = ["v4"] }
